// Vapi sends the End-of-Call Report in the request body.
// Typical Vapi payload shape:
// {
//   message: {
//     type: 'end-of-call-report',
//     call: { id, phoneNumberId, ... },
//     artifact: { transcript, recordingUrl, ... },
//     analysis: { summary, successEvaluation },
//     startedAt, endedAt,
//     endedReason
//   }
// }

const body = $input.item.json.body || $input.item.json;
const msg  = body.message || body;

const call     = msg.call || {};
const artifact = msg.artifact || {};
const analysis = msg.analysis || {};

const callId         = call.id || 'unknown';
const phoneNumber    = call.customer?.number || call.phoneNumberId || 'unknown';
const startedAt      = msg.startedAt || new Date().toISOString();
const endedAt        = msg.endedAt   || new Date().toISOString();
const endedReason    = msg.endedReason || 'unknown';

// Duration in seconds
let durationSec = 0;
if (startedAt && endedAt) {
  durationSec = Math.round((new Date(endedAt) - new Date(startedAt)) / 1000);
}

const transcript   = artifact.transcript   || '';
const recordingUrl = artifact.recordingUrl || '';
const summary      = analysis.summary           || '';
const outcome      = analysis.successEvaluation || 'unknown';

return [{
  json: {
    callId,
    phoneNumber,
    startedAt,
    endedAt,
    durationSec,
    endedReason,
    summary,
    outcome,
    transcript,
    recordingUrl,
    loggedAt: new Date().toISOString()
  }
}];
